import{_ as n,O as e,H as p,f as t,k as l,i}from"./chunks/framework.Pt2pSV98.js";const m=JSON.parse('{"title":"用 AI 做 PPT","description":"让 AI 帮你生成 PPT 大纲和内容，再用工具一键生成——从零到完成只需四步","frontmatter":{"title":"用 AI 做 PPT","description":"让 AI 帮你生成 PPT 大纲和内容，再用工具一键生成——从零到完成只需四步","difficulty":"beginner"},"headers":[],"relativePath":"practices/ai-ppt.md","filePath":"practices/ai-ppt.md"}'),o={name:"practices/ai-ppt.md"};function r(c,a,h,d,u,P){const s=e("DifficultyBadge");return p(),t("div",null,[l(s,{level:"beginner"}),a[0]||(a[0]=i(`<h1 id="用-ai-做-ppt" tabindex="-1">用 AI 做 PPT <a class="header-anchor" href="#用-ai-做-ppt" aria-label="Permalink to &quot;用 AI 做 PPT&quot;">​</a></h1><p>做 PPT 最头疼的不是排版，而是不知道写什么、怎么写。AI 可以帮你搞定最困难的内容部分，再用自动化工具生成，效率提升 10 倍。</p><h2 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to &quot;准备工作&quot;">​</a></h2><ul><li>一个 AI 对话工具（ChatGPT、Claude 等）</li><li>一个 PPT 自动生成工具（推荐 <a href="https://gamma.app" target="_blank" rel="noreferrer">Gamma</a>、<a href="https://www.beautiful.ai" target="_blank" rel="noreferrer">Beautiful.ai</a>，或用 ChatGPT Plus 直接生成）</li><li>确定你的 PPT 主题和受众</li></ul><hr><h2 id="第-1-步-让-ai-生成-ppt-大纲" tabindex="-1">第 1 步：让 AI 生成 PPT 大纲 <a class="header-anchor" href="#第-1-步-让-ai-生成-ppt-大纲" aria-label="Permalink to &quot;第 1 步：让 AI 生成 PPT 大纲&quot;">​</a></h2><p>先别急着写内容，让 AI 帮你搭好整体结构。好的大纲是 PPT 成功的一半。</p><h3 id="示例-prompt" tabindex="-1">示例 Prompt <a class="header-anchor" href="#示例-prompt" aria-label="Permalink to &quot;示例 Prompt&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我要做一个 15 页的 PPT，主题是&quot;人工智能如何改变教育行业&quot;，</span></span>
<span class="line"><span>面向教育工作者，时长 20 分钟。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请帮我设计一个完整的大纲，包括：</span></span>
<span class="line"><span>1. PPT 的章节划分（3-5 个章节）</span></span>
<span class="line"><span>2. 每页的标题</span></span>
<span class="line"><span>3. 每页的核心要点（2-3 个）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>要求：</span></span>
<span class="line"><span>- 结构清晰，从问题到方案，再到展望</span></span>
<span class="line"><span>- 每页信息量适中，不要太空也不要太满</span></span>
<span class="line"><span>- 加入实际案例增加说服力</span></span></code></pre></div><p>AI 会输出类似这样的结构：</p><blockquote><p><strong>第 1 章：AI 来了（3 页）</strong></p><ul><li>P1 封面 + P2 当下教育痛点 + P3 什么是 AI 教育</li></ul><p><strong>第 2 章：AI 怎么做（5 页）</strong></p><ul><li>P4 个性化学习 + P5 智能辅导 + P6 自动批改 + P7 案例+ P8 数据对比</li></ul></blockquote><p>如果某个章节不满意，直接让它调整：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第 2 章太长了，压缩到 3 页。把&quot;数据对比&quot;合并到案例页。</span></span></code></pre></div><hr><h2 id="第-2-步-让-ai-写详细内容" tabindex="-1">第 2 步：让 AI 写详细内容 <a class="header-anchor" href="#第-2-步-让-ai-写详细内容" aria-label="Permalink to &quot;第 2 步：让 AI 写详细内容&quot;">​</a></h2><p>大纲定了，逐页填充内容。一页一页来，不要一次性要太多。</p><h3 id="示例-prompt-1" tabindex="-1">示例 Prompt <a class="header-anchor" href="#示例-prompt-1" aria-label="Permalink to &quot;示例 Prompt&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>按照刚才的 PPT 大纲，请写第 4 页&quot;个性化学习&quot;的详细内容。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>这页要讲的核心信息是：</span></span>
<span class="line"><span>&quot;AI 通过分析学生的学习数据，为每个人定制学习路径和节奏。&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>格式要求：</span></span>
<span class="line"><span>- 标题：简短有力</span></span>
<span class="line"><span>- 正文：不超过 3 段，每段不超过 3 句话</span></span>
<span class="line"><span>- 如果有数据或对比，用要点列表呈现</span></span></code></pre></div><p>如果觉得内容太干，可以加料：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>加一个具体的小案例，比如某个学校用 AI 个性化学习后成绩提升了多少。</span></span>
<span class="line"><span>要有具体数字。</span></span></code></pre></div><hr><h2 id="第-3-步-让-ai-推荐配图和设计建议" tabindex="-1">第 3 步：让 AI 推荐配图和设计建议 <a class="header-anchor" href="#第-3-步-让-ai-推荐配图和设计建议" aria-label="Permalink to &quot;第 3 步：让 AI 推荐配图和设计建议&quot;">​</a></h2><p>内容有了，视觉也不能少。AI 可以帮你规划每页的视觉呈现。</p><h3 id="示例-prompt-2" tabindex="-1">示例 Prompt <a class="header-anchor" href="#示例-prompt-2" aria-label="Permalink to &quot;示例 Prompt&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我的 PPT 主题是&quot;AI 改变教育&quot;，请针对前面的大纲，给每一页推荐：</span></span>
<span class="line"><span>1. 适合的配图类型（示意图、数据图表、真实照片、图标）</span></span>
<span class="line"><span>2. 配色建议（主色、辅色、强调色）</span></span>
<span class="line"><span>3. 布局建议（左图右文 / 上文下图 / 全图 / 三栏）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>尽量具体。比如不要只说&quot;数据图表&quot;，要说清楚&quot;柱状图对比 AI 辅助前后成绩变化&quot;。</span></span></code></pre></div><p>AI 会给每页具体的视觉方案，你用这些描述去配图软件里搜关键词就能找到合适的素材。</p><hr><h2 id="第-4-步-用工具自动生成-ppt" tabindex="-1">第 4 步：用工具自动生成 PPT <a class="header-anchor" href="#第-4-步-用工具自动生成-ppt" aria-label="Permalink to &quot;第 4 步：用工具自动生成 PPT&quot;">​</a></h2><p>内容齐了，最后一步是用工具把文字变成真正的 PPT。两个推荐方案：</p><h3 id="方案-a-gamma-app-免费版够用" tabindex="-1">方案 A：Gamma.app（免费版够用） <a class="header-anchor" href="#方案-a-gamma-app-免费版够用" aria-label="Permalink to &quot;方案 A：Gamma.app（免费版够用）&quot;">​</a></h3><p>把 AI 生成的大纲贴进去，Gamma 会自动生成一套设计精美的 PPT，你只需要微调。</p><h3 id="方案-b-chatgpt-claude-直出-ppt" tabindex="-1">方案 B：ChatGPT / Claude 直出 PPT <a class="header-anchor" href="#方案-b-chatgpt-claude-直出-ppt" aria-label="Permalink to &quot;方案 B：ChatGPT / Claude 直出 PPT&quot;">​</a></h3><p>如果你用的是付费版，可以试试让 AI 直接生成可下载的 PPT 文件：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请把上述 PPT 大纲和内容整理成一个结构化文本，</span></span>
<span class="line"><span>每个页面用 &quot;---&quot; 分隔，第一行是标题，后面是内容要点。</span></span>
<span class="line"><span>我准备把这个结构导入到 Gamma 中一键生成 PPT。</span></span></code></pre></div><h3 id="方案-c-手动拼装-适合想完全控制效果的人" tabindex="-1">方案 C：手动拼装（适合想完全控制效果的人） <a class="header-anchor" href="#方案-c-手动拼装-适合想完全控制效果的人" aria-label="Permalink to &quot;方案 C：手动拼装（适合想完全控制效果的人）&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请把我这个 PPT 的每一页内容压缩成 3-5 个关键词或短语，</span></span>
<span class="line"><span>方便我复制到 PPT 模板的文本框里。</span></span></code></pre></div><hr><h2 id="关键技巧总结" tabindex="-1">关键技巧总结 <a class="header-anchor" href="#关键技巧总结" aria-label="Permalink to &quot;关键技巧总结&quot;">​</a></h2><ol><li><strong>先定结构再填内容</strong>：不要一上来就写具体内容，先搭好框架</li><li><strong>逐页迭代</strong>：一次问一页的内容，质量比一次问全部高很多</li><li><strong>带着数据去问</strong>：告诉 AI 你的品牌色、Logo、目标受众，输出更精准</li><li><strong>AI 负责内容，工具负责排版</strong>：各司其职，效率最高</li></ol><hr><h2 id="关联阅读" tabindex="-1">关联阅读 <a class="header-anchor" href="#关联阅读" aria-label="Permalink to &quot;关联阅读&quot;">​</a></h2><ul><li><a href="/ai-knowledge/tools/chatgpt.html">ChatGPT 工具详解</a></li><li><a href="/ai-knowledge/prompts/principles.html">清晰的 Prompt 怎么写</a></li><li><a href="/ai-knowledge/practices/ai-translation.html">用 AI 做翻译</a></li></ul>`,42))])}const g=n(o,[["render",r]]);export{m as __pageData,g as default};
